1	'use strict';
2	/**
3	 * GSD-T Token Capture Wrapper (M41 D1)
4	 *
5	 * Single reusable module every GSD-T spawn call site uses. Parses the
6	 * `usage` envelope from Claude's result frame, appends a row to
7	 * `.gsd-t/token-log.md`, and appends a schema-v1 JSONL record to
8	 * `.gsd-t/metrics/token-usage.jsonl`.
9	 *
10	 * Zero external deps. `.cjs` so it loads in both ESM-default projects
11	 * and CJS projects without transpilation.
12	 *
13	 * Contracts:
14	 *   - .gsd-t/contracts/metrics-schema-contract.md (schema v1)
15	 *   - .gsd-t/contracts/stream-json-sink-contract.md v1.1.0 (usage semantics)
16	 *
17	 * Missing `usage` → write `—` in Tokens column. Never `0`, never `N/A`.
18	 */
19	
20	const fs = require('fs');
21	const path = require('path');
22	
23	const SCHEMA_VERSION = 2;
24	
25	const NEW_HEADER = '| Datetime-start | Datetime-end | Command | Step | Model | Duration(s) | Tokens | Notes | Domain | Task | Ctx% |';
26	const NEW_SEP    = '|---|---|---|---|---|---|---|---|---|---|---|';
27	
28	function pad2(n) { return String(n).padStart(2, '0'); }
29	function fmtDateTime(d) {
30	  return `${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())} ${pad2(d.getHours())}:${pad2(d.getMinutes())}`;
31	}
32	
33	function _parseUsageFromResult(result) {
34	  if (!result || typeof result !== 'object') return undefined;
35	  if (result.usage && typeof result.usage === 'object') return result.usage;
36	  if (result.result && typeof result.result === 'object' && result.result.usage && typeof result.result.usage === 'object') {
37	    return result.result.usage;
38	  }
39	  return undefined;
40	}
41	
42	function _formatTokensCell(usage) {
43	  if (!usage || typeof usage !== 'object') return '—';
44	  const inp = Number(usage.input_tokens || 0);
45	  const out = Number(usage.output_tokens || 0);
46	  const cr  = Number(usage.cache_read_input_tokens || 0);
47	  const cc  = Number(usage.cache_creation_input_tokens || 0);
48	  const costNum = (typeof usage.total_cost_usd === 'number') ? usage.total_cost_usd : (typeof usage.cost_usd === 'number' ? usage.cost_usd : null);
49	  const cost = (costNum == null) ? '—' : `$${costNum.toFixed(2)}`;
50	  if (!inp && !out && !cr && !cc && cost === '—') return '—';
51	  return `in=${inp} out=${out} cr=${cr} cc=${cc} ${cost}`;
52	}
53	
54	function _ensureDir(p) {
55	  const dir = path.dirname(p);
56	  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
57	}
58	
59	function _ensureTokenLogHeader(tokenLogPath) {
60	  if (!fs.existsSync(tokenLogPath)) {
61	    _ensureDir(tokenLogPath);
62	    fs.writeFileSync(tokenLogPath, `# GSD-T Token Log\n\n${NEW_HEADER}\n${NEW_SEP}\n`);
63	    return;
64	  }
65	  const text = fs.readFileSync(tokenLogPath, 'utf8');
66	  if (text.includes(NEW_HEADER)) return;
67	  // Old header detection: first header line that starts with `| Datetime-start`
68	  const lines = text.split('\n');
69	  const headerIdx = lines.findIndex(l => /^\|\s*Datetime-start\s*\|/.test(l));
70	  if (headerIdx < 0) {
71	    // No header at all — append new one
72	    fs.writeFileSync(tokenLogPath, text.trimEnd() + `\n\n${NEW_HEADER}\n${NEW_SEP}\n`);
73	    return;
74	  }
75	  // Replace old header + separator with new header + separator, preserve existing rows
76	  const sepIdx = headerIdx + 1;
77	  lines[headerIdx] = NEW_HEADER;
78	  if (lines[sepIdx] && /^\|[\s\-|]+\|$/.test(lines[sepIdx])) {
79	    lines[sepIdx] = NEW_SEP;
80	  } else {
81	    lines.splice(sepIdx, 0, NEW_SEP);
82	  }
83	  fs.writeFileSync(tokenLogPath, lines.join('\n'));
84	}
85	
86	function _appendTokenLogRow(tokenLogPath, row) {
87	  _ensureTokenLogHeader(tokenLogPath);
88	  const line = `| ${row.startedAt} | ${row.endedAt} | ${row.command} | ${row.step} | ${row.model} | ${row.durationSec}s | ${row.tokensCell} | ${row.notes} | ${row.domain} | ${row.task} | ${row.ctxPct} |\n`;
89	  fs.appendFileSync(tokenLogPath, line);
90	}
91	
92	function _appendJsonlRecord(jsonlPath, record) {
93	  _ensureDir(jsonlPath);
94	  fs.appendFileSync(jsonlPath, JSON.stringify(record) + '\n');
95	}
96	
97	function _buildJsonlRecord({ command, step, model, startedAt, endedAt, durationSec, usage, domain, task, notes, ctxPct, milestone, source, sessionId, turnId, sessionType, toolAttribution, compactionPressure }) {
98	  const u = usage || {};
99	  const cost = (typeof u.total_cost_usd === 'number') ? u.total_cost_usd : (typeof u.cost_usd === 'number' ? u.cost_usd : null);
100	  const rec = {

1	'use strict';
2	/**
3	 * GSD-T Token Log Regenerator (M43 D3)
4	 *
5	 * Reads `.gsd-t/metrics/token-usage.jsonl` end-to-end and writes
6	 * `.gsd-t/token-log.md` deterministically. Per metrics-schema-contract v2
7	 * §Derived Artifact, `token-log.md` is a regenerated view post-v2.
8	 *
9	 * Sort (v2 §5): startedAt asc → session_id asc → turn_id asc.
10	 * Numeric turn_ids sort numerically; mixed/non-numeric falls back to lex.
11	 *
12	 * Idempotent and deterministic: running twice produces byte-identical output.
13	 */
14	
15	const fs = require('fs');
16	const path = require('path');
17	
18	const capture = require('./gsd-t-token-capture.cjs');
19	const { NEW_HEADER, NEW_SEP, _formatTokensCell } = capture;
20	
21	function _readJsonl(jsonlPath) {
22	  if (!fs.existsSync(jsonlPath)) return [];
23	  const text = fs.readFileSync(jsonlPath, 'utf8');
24	  const rows = [];
25	  for (const line of text.split('\n')) {
26	    const s = line.trim();
27	    if (!s) continue;
28	    try { rows.push(JSON.parse(s)); }
29	    catch (_) { /* skip malformed line */ }
30	  }
31	  return rows;
32	}
33	
34	function _tokenCellFromRow(row) {
35	  if (!row.hasUsage) return '—';
36	  const u = {
37	    input_tokens: row.inputTokens || 0,
38	    output_tokens: row.outputTokens || 0,
39	    cache_read_input_tokens: row.cacheReadInputTokens || 0,
40	    cache_creation_input_tokens: row.cacheCreationInputTokens || 0,
41	    total_cost_usd: (typeof row.costUSD === 'number') ? row.costUSD : undefined,
42	  };
43	  return _formatTokensCell(u);
44	}
45	
46	function _cmpStart(a, b) {
47	  const av = a.startedAt || '';
48	  const bv = b.startedAt || '';
49	  if (av < bv) return -1;
50	  if (av > bv) return 1;
51	  return 0;
52	}
53	
54	function _cmpSession(a, b) {
55	  const av = a.session_id == null ? '' : String(a.session_id);
56	  const bv = b.session_id == null ? '' : String(b.session_id);
57	  if (av < bv) return -1;
58	  if (av > bv) return 1;
59	  return 0;
60	}
61	
62	function _cmpTurn(a, b) {
63	  const av = a.turn_id == null ? '' : String(a.turn_id);
64	  const bv = b.turn_id == null ? '' : String(b.turn_id);
65	  const an = Number(av), bn = Number(bv);
66	  if (av !== '' && bv !== '' && Number.isFinite(an) && Number.isFinite(bn)) {
67	    return an - bn;
68	  }
69	  if (av < bv) return -1;
70	  if (av > bv) return 1;
71	  return 0;
72	}
73	
74	function sortRows(rows) {
75	  return rows.slice().sort((a, b) =>
76	    _cmpStart(a, b) || _cmpSession(a, b) || _cmpTurn(a, b)
77	  );
78	}
79	
80	function _durationCell(row) {
81	  const ms = Number(row.durationMs || 0);
82	  return `${Math.max(0, Math.round(ms / 1000))}s`;
83	}
84	
85	function _renderRow(row) {
86	  const tokensCell = _tokenCellFromRow(row);
87	  const notes  = (row.notes  == null || row.notes  === '') ? '-' : String(row.notes).replace(/\|/g, '\\|');
88	  const domain = (row.domain == null || row.domain === '') ? '-' : String(row.domain);
89	  const task   = (row.task   == null || row.task   === '') ? '-' : String(row.task);
90	  const ctxPct = (row.ctxPct == null) ? 'N/A' : String(row.ctxPct);
91	  return `| ${row.startedAt || ''} | ${row.endedAt || ''} | ${row.command || ''} | ${row.step || ''} | ${row.model || ''} | ${_durationCell(row)} | ${tokensCell} | ${notes} | ${domain} | ${task} | ${ctxPct} |`;
92	}
93	
94	function renderMarkdown(rows) {
95	  const sorted = sortRows(rows);
96	  const lines = ['# GSD-T Token Log', '', NEW_HEADER, NEW_SEP];
97	  for (const r of sorted) lines.push(_renderRow(r));
98	  lines.push('');
99	  return lines.join('\n');
100	}
101	
102	/**
103	 * Regenerate token-log.md from token-usage.jsonl.
104	 * @param {object} [opts]
105	 * @param {string} [opts.projectDir='.']
106	 * @param {string} [opts.jsonlPath]     override input path
107	 * @param {string} [opts.tokenLogPath]  override output path
108	 * @returns {{ wrote: string, rowCount: number }}
109	 */
110	function regenerateLog(opts = {}) {
111	  const projectDir = opts.projectDir || '.';
112	  const jsonlPath = opts.jsonlPath || path.join(projectDir, '.gsd-t', 'metrics', 'token-usage.jsonl');
113	  const tokenLogPath = opts.tokenLogPath || path.join(projectDir, '.gsd-t', 'token-log.md');
114	  const rows = _readJsonl(jsonlPath);
115	  const markdown = renderMarkdown(rows);
116	  const dir = path.dirname(tokenLogPath);
117	  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
118	  fs.writeFileSync(tokenLogPath, markdown);
119	  return { wrote: tokenLogPath, rowCount: rows.length };
120	}
121	
122	module.exports = {
123	  regenerateLog,
124	  renderMarkdown,
125	  sortRows,
126	  _readJsonl,
127	  _renderRow,
128	  _tokenCellFromRow,
129	};
