1	#!/usr/bin/env node
2	
3	/**
4	 * GSD-T Heartbeat — Claude Code Hook Event Writer
5	 *
6	 * Writes structured events to .gsd-t/heartbeat-{session_id}.jsonl
7	 * Installed as an async hook for multiple Claude Code events.
8	 *
9	 * Events captured:
10	 *   SessionStart, PostToolUse, SubagentStart, SubagentStop,
11	 *   TaskCompleted, TeammateIdle, Notification, Stop, SessionEnd
12	 */
13	
14	const fs = require("fs");
15	const path = require("path");
16	
17	const MAX_STDIN = 1024 * 1024; // 1MB — prevent OOM from unbounded input
18	const SAFE_SID = /^[a-zA-Z0-9_-]+$/; // Allowlist for session_id — blocks path traversal
19	const MAX_AGE_MS = 7 * 24 * 60 * 60 * 1000; // 7 days — auto-cleanup threshold
20	
21	// ─── Exports (for testing) ───────────────────────────────────────────────────
22	module.exports = { scrubSecrets, scrubUrl, buildEvent, summarize, shortPath, buildEventStreamEntry, appendToEventsFile };
23	
24	// ─── Main (stdin processing) ─────────────────────────────────────────────────
25	if (require.main === module) {
26	
27	let input = "";
28	let aborted = false;
29	process.stdin.setEncoding("utf8");
30	process.stdin.on("data", (d) => {
31	  input += d;
32	  if (input.length > MAX_STDIN) {
33	    aborted = true;
34	    process.stdin.destroy();
35	  }
36	});
37	process.stdin.on("end", () => {
38	  if (aborted) return; // Silently discard oversized input
39	  try {
40	    const hook = JSON.parse(input);
41	    const dir = hook.cwd || process.cwd();
42	
43	    // Validate cwd is absolute path
44	    if (!path.isAbsolute(dir)) return;
45	
46	    const gsdtDir = path.join(dir, ".gsd-t");
47	    if (!fs.existsSync(gsdtDir)) return;
48	
49	    const sid = hook.session_id || "unknown";
50	
51	    // Validate session_id — block path traversal (e.g., "../../etc/evil")
52	    if (!SAFE_SID.test(sid)) return;
53	
54	    const file = path.join(gsdtDir, `heartbeat-${sid}.jsonl`);
55	
56	    // Verify resolved path is still within .gsd-t/ directory
57	    const resolvedFile = path.resolve(file);
58	    const resolvedDir = path.resolve(gsdtDir);
59	    if (!resolvedFile.startsWith(resolvedDir + path.sep)) return;
60	
61	    const event = buildEvent(hook);
62	    if (event) {
63	      if (hook.hook_event_name === "SessionStart") cleanupOldHeartbeats(gsdtDir);
64	      // Symlink check — prevent redirection of event data to arbitrary files
65	      try { if (fs.lstatSync(file).isSymbolicLink()) return; } catch { /* file doesn't exist yet — safe */ }
66	      fs.appendFileSync(file, JSON.stringify(event) + "\n");
67	    }
68	
69	    // Event stream enrichment — additive only, does not affect heartbeat writes above
70	    const streamEntry = buildEventStreamEntry(hook);
71	    if (streamEntry) appendToEventsFile(gsdtDir, streamEntry);
72	  } catch (e) {
73	    // Silent failure — never interfere with Claude Code
74	  }
75	});
76	
77	} // end require.main
78	
79	function cleanupOldHeartbeats(gsdtDir) {
80	  try {
81	    const files = fs.readdirSync(gsdtDir);
82	    const now = Date.now();
83	    for (const f of files) {
84	      if (!f.startsWith("heartbeat-") || !f.endsWith(".jsonl")) continue;
85	      const fp = path.join(gsdtDir, f);
86	      const stat = fs.lstatSync(fp);
87	      if (stat.isSymbolicLink()) continue; // Don't follow symlinks
88	      if (now - stat.mtimeMs > MAX_AGE_MS) {
89	        fs.unlinkSync(fp);
90	      }
91	    }
92	  } catch {
93	    // Silent failure — never interfere with Claude Code
94	  }
95	}
96	
97	const EVENT_HANDLERS = {
98	  SessionStart: (h) => ({ evt: "session_start", data: { source: h.source, model: h.model } }),
99	  PostToolUse: (h) => ({ evt: "tool", tool: h.tool_name, agent_id: h.agent_id || null, data: summarize(h.tool_name, h.tool_input) }),
100	  SubagentStart: (h) => ({ evt: "agent_spawn", data: { agent_id: h.agent_id, agent_type: h.agent_type, parent_id: h.parent_agent_id || h.session_id, tokens: null } }),
101	  SubagentStop: (h) => ({ evt: "agent_stop", data: { agent_id: h.agent_id, agent_type: h.agent_type, parent_id: h.parent_agent_id || h.session_id, tokens: null } }),
102	  TaskCompleted: (h) => ({ evt: "task_done", data: { task: h.task_subject, agent: h.teammate_name } }),
103	  TeammateIdle: (h) => ({ evt: "agent_idle", data: { agent: h.teammate_name, team: h.team_name } }),
104	  Notification: (h) => ({ evt: "notification", data: { message: scrubSecrets(h.message), title: scrubSecrets(h.title) } }),
105	  Stop: () => ({ evt: "session_stop" }),
106	  SessionEnd: (h) => ({ evt: "session_end", data: { reason: h.reason } }),
107	};
108	
109	function buildEvent(hook) {
110	  const handler = EVENT_HANDLERS[hook.hook_event_name];
111	  if (!handler) return null;
112	  return { ts: new Date().toISOString(), sid: hook.session_id, ...handler(hook) };
113	}
114	
115	// Patterns that indicate sensitive values in CLI commands
116	const SECRET_FLAGS = /(--(password|token|secret|api[-_]?key|auth|credential|private[-_]?key)[\s=])\S+/gi;
117	const SECRET_SHORT = /(\s-p\s)\S+/gi;
118	const SECRET_ENV = /((API_KEY|SECRET|TOKEN|PASSWORD|BEARER|AUTH_TOKEN|PRIVATE_KEY|ACCESS_KEY|SECRET_KEY)=)\S+/gi;
119	const BEARER_HEADER = /(bearer\s+)\S+/gi;
120	
121	function scrubSecrets(cmd) {
122	  if (!cmd) return cmd;
123	  return cmd
124	    .replace(SECRET_FLAGS, "$1***")
125	    .replace(SECRET_SHORT, "$1***")
126	    .replace(SECRET_ENV, "$1***")
127	    .replace(BEARER_HEADER, "$1***");
128	}
129	
130	function scrubUrl(url) {
131	  if (!url) return url;
132	  try {
133	    const u = new URL(url);
134	    if (!u.search) return url;
135	    for (const key of u.searchParams.keys()) {
136	      u.searchParams.set(key, "***");
137	    }
138	    return u.toString();
139	  } catch { return url; }
140	}
141	
142	function summarize(tool, input) {
143	  if (!tool || !input) return {};
144	  switch (tool) {
145	    case "Read":
146	    case "Edit":
147	    case "Write":
148	      return { file: shortPath(input.file_path) };
149	    case "Bash":
150	      return {
151	        cmd: scrubSecrets((input.command || "").slice(0, 150)),
152	        desc: input.description,
153	      };
154	    case "Grep":
155	      return { pattern: input.pattern, path: shortPath(input.path) };
156	    case "Glob":
157	      return { pattern: input.pattern };
158	    case "Task":
159	      return { desc: input.description, type: input.subagent_type };
160	    case "WebSearch":
161	      return { query: input.query };
162	    case "WebFetch":
163	      return { url: scrubUrl(input.url) };
164	    case "NotebookEdit":
165	      return { file: shortPath(input.notebook_path) };
166	    default:
167	      return {};
168	  }
169	}
