71	  const text = fs.readFileSync(transcriptPath, 'utf8');
72	  const lines = text.split(/\r?\n/);
73	  const out = [];
74	  let turnIndex = 0;
75	  for (const line of lines) {
76	    const j = _parseJsonLineSafe(line);
77	    if (!j) continue;
78	    const msg = j.message;
79	    if (!msg || typeof msg !== 'object') continue;
80	    if (msg.role && msg.role !== 'assistant') continue;
81	    const usage = msg.usage;
82	    if (!usage || typeof usage !== 'object') continue;
83	    out.push({
84	      messageId: msg.id || j.uuid || null,
85	      model: msg.model || null,
86	      usage,
87	      timestamp: j.timestamp || null,
88	      turnIndex: turnIndex++,
