235	function handleTranscriptKill(req, res, spawnId, projectDir) {
236	  if (!isValidSpawnId(spawnId)) { res.writeHead(400); res.end("Invalid spawn id"); return; }
237	  const idx = readTranscriptsIndex(projectDir);
238	  const i = idx.spawns.findIndex((s) => s.spawnId === spawnId);
239	  if (i < 0) { res.writeHead(404, { "Content-Type": "application/json" }); res.end(JSON.stringify({ error: "unknown_spawn" })); return; }
240	  const entry = idx.spawns[i];
241	  const pid = entry.workerPid;
242	  if (!pid || typeof pid !== "number") {
243	    res.writeHead(409, { "Content-Type": "application/json" });
244	    res.end(JSON.stringify({ error: "no_pid_recorded" }));
245	    return;
246	  }
247	  try {
248	    process.kill(pid, "SIGTERM");
249	    idx.spawns[i].status = "stopped";
250	    idx.spawns[i].endedAt = idx.spawns[i].endedAt || new Date().toISOString();
251	    writeTranscriptsIndex(projectDir, idx);
252	    res.writeHead(200, { "Content-Type": "application/json" });
253	    res.end(JSON.stringify({ status: "stopped", pid }));
254	  } catch (err) {
255	    if (err.code === "ESRCH") {
256	      // Process already gone — treat as success and mark ended
257	      idx.spawns[i].status = idx.spawns[i].status === "running" ? "stopped" : idx.spawns[i].status;
258	      idx.spawns[i].endedAt = idx.spawns[i].endedAt || new Date().toISOString();
259	      writeTranscriptsIndex(projectDir, idx);
260	      res.writeHead(200, { "Content-Type": "application/json" });
261	      res.end(JSON.stringify({ status: "already_stopped", pid }));
262	      return;
263	    }
264	    if (err.code === "EPERM") {
265	      res.writeHead(403, { "Content-Type": "application/json" });
266	      res.end(JSON.stringify({ error: "permission_denied", pid }));
267	      return;
268	    }
269	    res.writeHead(500, { "Content-Type": "application/json" });
270	    res.end(JSON.stringify({ error: String(err.message || err) }));
271	  }
272	}
