286	function handleTranscriptStream(req, res, spawnId, projectDir) {
287	  if (!isValidSpawnId(spawnId)) { res.writeHead(400); res.end("Invalid spawn id"); return; }
288	  const filePath = path.join(transcriptsDir(projectDir), `${spawnId}.ndjson`);
289	  let exists = true;
290	  let fileSize = 0;
291	  try { fileSize = fs.statSync(filePath).size; } catch { exists = false; }
292	
293	  res.writeHead(200, SSE_HEADERS);
294	
295	  // Consult the transcripts index — if the spawn is already finished we
296	  // replay and close instead of attaching a live tail.
297	  const entry = readIndexEntry(projectDir, spawnId);
298	  const finishedStatuses = ["done", "failed", "stopped"];
299	  const isFinished = !!(entry && entry.status && finishedStatuses.includes(entry.status));
300	
301	  // Replay: read the full file from byte 0 and send each line.
302	  let replayedBytes = 0;
303	  if (exists) {
304	    try {
305	      const full = fs.readFileSync(filePath, "utf8");
306	      replayedBytes = Buffer.byteLength(full, "utf8");
307	      full.split("\n").forEach((line) => {
308	        if (line.length > 0) {
309	          try { res.write("data: " + line + "\n\n"); } catch { /* gone */ }
310	        }
311	      });
312	    } catch { /* empty transcript */ }
313	  }
314	
315	  // Finished spawn → emit end event and close the stream. No tail, no keepalive.
316	  if (isFinished) {
317	    const endPayload = JSON.stringify({
318	      status: entry.status,
319	      endedAt: entry.endedAt || null,
320	    });
321	    try { res.write("event: end\ndata: " + endPayload + "\n\n"); } catch { /* gone */ }
322	    try { res.end(); } catch { /* gone */ }
323	    return;
324	  }
325	
326	  // Missing file — tell the viewer the stream is live but empty. fs.watchFile
327	  // needs the file to exist, so we skip the tail here. A running producer
328	  // will have created the file already (the finished-spawn branch above
329	  // catches the post-hoc teed case via index status).
330	  if (!exists) {
331	    const waitingPayload = JSON.stringify({
332	      status: "waiting",
333	      reason: "no transcript file yet",
334	    });
335	    try { res.write("event: status\ndata: " + waitingPayload + "\n\n"); } catch { /* gone */ }
336	    const timer = setInterval(() => { try { res.write(": keepalive\n\n"); } catch { clearInterval(timer); } }, KEEPALIVE_MS);
337	    req.on("close", () => { clearInterval(timer); });
338	    return;
339	  }
340	
341	  // Empty file — producer hasn't written anything yet. Emit a status frame
342	  // so the viewer knows the stream is live but the file is 0 bytes, then
343	  // attach the live tail so we pick up writes as they arrive.
344	  if (fileSize === 0) {
345	    const emptyPayload = JSON.stringify({
346	      status: "empty",
347	      reason: "transcript file exists but is empty",
348	    });
349	    try { res.write("event: status\ndata: " + emptyPayload + "\n\n"); } catch { /* gone */ }
350	  }
351	
352	  // Tail: from replayedBytes onward. We reuse the tailer, but seed offset
353	  // with what we already replayed so we don't double-send.
354	  let offset = replayedBytes;
355	  let buf = "";
356	  const processNewData = () => {
357	    let stat;
358	    try { stat = fs.statSync(filePath); } catch { return; }
359	    if (stat.size <= offset) return;
360	    const fd = fs.openSync(filePath, "r");
361	    try {
362	      const b = Buffer.alloc(stat.size - offset);
363	      fs.readSync(fd, b, 0, b.length, offset);
364	      buf += b.toString("utf8");
365	      offset = stat.size;
366	    } finally { fs.closeSync(fd); }
367	    let nl;
368	    while ((nl = buf.indexOf("\n")) >= 0) {
369	      const line = buf.slice(0, nl);
370	      buf = buf.slice(nl + 1);
371	      if (line.length > 0) {
372	        try { res.write("data: " + line + "\n\n"); } catch { /* gone */ }
373	      }
374	    }
375	  };
376	  fs.watchFile(filePath, { interval: 500, persistent: true }, processNewData);
377	  const unwatchFile = () => fs.unwatchFile(filePath, processNewData);
378	
379	  const timer = setInterval(() => { try { res.write(": keepalive\n\n"); } catch { clearInterval(timer); } }, KEEPALIVE_MS);
380	  req.on("close", () => { clearInterval(timer); if (unwatchFile) unwatchFile(); });
381	}
