383	function startServer(port, eventsDir, htmlPath, projectDir, transcriptHtmlPath) {
384	  const projDir = projectDir || path.resolve(eventsDir, "..", "..");
385	  const tHtmlPath = transcriptHtmlPath || path.join(path.dirname(htmlPath), "gsd-t-transcript.html");
386	  const server = http.createServer((req, res) => {
387	    const url = req.url.split("?")[0];
388	    if (url === "/" || url === "") return handleRoot(req, res, htmlPath);
389	    if (url === "/events") return handleEvents(req, res, eventsDir);
390	    if (url === "/metrics") return handleMetrics(req, res, projDir);
391	    if (url === "/ping") return handlePing(req, res, port);
392	    if (url === "/stop") return handleStop(req, res, server);
393	    if (url === "/transcripts") return handleTranscriptsList(req, res, projDir);
394	    // POST /transcript/:spawnId/kill — SIGTERM the recorded workerPid
395	    const killMatch = url.match(/^\/transcript\/([^/]+)\/kill$/);
396	    if (killMatch && req.method === "POST") return handleTranscriptKill(req, res, decodeURIComponent(killMatch[1]), projDir);
397	    // /transcript/:spawnId/stream — SSE tail of per-spawn ndjson
398	    const streamMatch = url.match(/^\/transcript\/([^/]+)\/stream$/);
399	    if (streamMatch) return handleTranscriptStream(req, res, decodeURIComponent(streamMatch[1]), projDir);
400	    // /transcript/:spawnId — HTML viewer page
401	    const pageMatch = url.match(/^\/transcript\/([^/]+)$/);
402	    if (pageMatch) return handleTranscriptPage(req, res, decodeURIComponent(pageMatch[1]), tHtmlPath);
403	    res.writeHead(404); res.end("Not found");
404	  });
405	  server.listen(port);
406	  return { server, url: `http://localhost:${port}` };
407	}
