430	if (require.main === module) {
431	  const argv = process.argv.slice(2);
432	  const getArg = (flag) => { const i = argv.indexOf(flag); return i >= 0 ? argv[i + 1] : null; };
433	  const hasFlag = (f) => argv.includes(f);
434	  const projectDir = process.env.GSD_T_PROJECT_DIR || process.cwd();
435	  const port = resolvePort({ argPort: getArg("--port"), projectDir });
436	  const eventsDir = getArg("--events") || findEventsDir(projectDir);
437	  const pidFile = path.join(projectDir, ".gsd-t", "dashboard.pid");
438	  const htmlPath = path.join(__dirname, "gsd-t-dashboard.html");
439	  const transcriptHtmlPath = path.join(__dirname, "gsd-t-transcript.html");
440	
441	  if (hasFlag("--stop")) {
442	    try { const pid = parseInt(fs.readFileSync(pidFile, "utf8").trim(), 10); process.kill(pid); fs.unlinkSync(pidFile); }
443	    catch (e) { process.stderr.write("No running server: " + e.message + "\n"); }
444	    process.exit(0);
445	  }
446	  if (hasFlag("--detach")) {
447	    const child = spawn(process.execPath, [__filename, ...argv.filter((a) => a !== "--detach")], { detached: true, stdio: "ignore" });
448	    child.unref();
449	    try { fs.mkdirSync(path.dirname(pidFile), { recursive: true }); } catch { /* exists */ }
450	    fs.writeFileSync(pidFile, String(child.pid));
451	    process.exit(0);
452	  }
453	  const { server, url } = startServer(port, eventsDir, htmlPath, projectDir, transcriptHtmlPath);
454	  process.stdout.write("GSD-T Dashboard: " + url + "\n");
455	  function cleanup() { try { fs.unlinkSync(pidFile); } catch { /* ok */ } server.close(() => process.exit(0)); }
456	  process.on("SIGTERM", cleanup);
457	  process.on("SIGINT", cleanup);
458	}
