86	<body data-spawn-id="__SPAWN_ID__">
87	  <header>
88	    <div class="title">GSD-T Transcript</div>
89	    <div class="spawn-id" id="hdr-spawn-id"></div>
90	    <div class="status" id="hdr-status"><span class="dot"></span><span class="label">connecting…</span></div>
91	  </header>
92	  <aside>
93	    <h3>Spawns</h3>
94	    <div class="tree" id="tree"></div>
95	  </aside>
96	  <main id="stream"></main>
97	  <button class="jump-to-live" id="jump-btn">↓ Jump to live</button>
98	
99	  <script>
100	    (function () {
101	      'use strict';
102	
103	      const spawnId = document.body.getAttribute('data-spawn-id');
104	      document.getElementById('hdr-spawn-id').textContent = spawnId;
105	
106	      const stream = document.getElementById('stream');
107	      const statusEl = document.getElementById('hdr-status');
108	      const statusLabel = statusEl.querySelector('.label');
109	      const jumpBtn = document.getElementById('jump-btn');
110	
111	      // Pair tool_result → tool_use by tool_use_id so the renderer can place
112	      // the result next to the call even when they come as separate frames.
113	      const toolUseById = new Map();
114	
115	      let autoScroll = true;
116	
117	      function setStatus(cls, text) {
118	        statusEl.className = 'status ' + cls;
119	        statusLabel.textContent = text;
120	      }
121	
122	      function atBottom() {
123	        return window.innerHeight + window.scrollY >= document.body.offsetHeight - 40;
124	      }
125	
126	      window.addEventListener('scroll', () => {
127	        if (atBottom()) { autoScroll = true; jumpBtn.classList.remove('visible'); }
128	        else { autoScroll = false; jumpBtn.classList.add('visible'); }
129	      });
130	
131	      jumpBtn.addEventListener('click', () => {
132	        autoScroll = true;
133	        window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
134	        jumpBtn.classList.remove('visible');
135	      });
136	
137	      function appendFrame(el) {
138	        stream.appendChild(el);
139	        if (autoScroll) {
140	          requestAnimationFrame(() => window.scrollTo(0, document.body.scrollHeight));
141	        }
142	      }
143	
144	      function renderSystem(frame) {
145	        const div = document.createElement('div');
146	        div.className = 'frame system';
147	        const sid = frame.session_id ? ' session=' + frame.session_id.slice(0, 8) : '';
148	        const model = frame.model ? ' model=' + frame.model : '';
149	        const subtype = frame.subtype ? ' ' + frame.subtype : '';
150	        div.textContent = 'system' + subtype + sid + model;
151	        appendFrame(div);
152	      }
153	
154	      function renderUserMessage(content) {
155	        const div = document.createElement('div');
156	        div.className = 'frame user';
157	        const p = document.createElement('span');
158	        p.className = 'prefix';
159	        p.textContent = '>';
160	        div.appendChild(p);
161	        const span = document.createElement('span');
162	        span.textContent = typeof content === 'string' ? content : JSON.stringify(content);
163	        div.appendChild(span);
164	        appendFrame(div);
165	      }
166	
167	      function renderAssistantText(text) {
168	        const div = document.createElement('div');
169	        div.className = 'frame assistant-text';
170	        div.textContent = text;
171	        appendFrame(div);
172	      }
173	
174	      function renderThinking(text) {
175	        const d = document.createElement('details');
176	        d.className = 'frame thinking';
177	        const s = document.createElement('summary');
178	        s.textContent = '✻ Thinking (' + text.length + ' chars)';
179	        d.appendChild(s);
180	        const pre = document.createElement('div');
181	        pre.textContent = text;
182	        d.appendChild(pre);
183	        appendFrame(d);
184	      }
185	
186	      function toolUsePreview(input) {
187	        if (!input || typeof input !== 'object') return '';
188	        // Surface the most useful single arg: file_path, command, pattern, path, description
189	        const keys = ['file_path', 'command', 'pattern', 'path', 'description', 'prompt'];
190	        for (const k of keys) {
191	          if (typeof input[k] === 'string') {
192	            const v = input[k];
193	            return k + '="' + (v.length > 80 ? v.slice(0, 77) + '…' : v) + '"';
194	          }
195	        }
196	        const first = Object.keys(input)[0];
197	        if (first) return first + '=…';
198	        return '';
199	      }
200	
201	      function renderToolUse(block) {
202	        const d = document.createElement('details');
203	        d.className = 'frame tool-use';
204	        const s = document.createElement('summary');
205	        s.textContent = block.name + '(' + toolUsePreview(block.input) + ')';
206	        d.appendChild(s);
207	        const pre = document.createElement('pre');
208	        try { pre.textContent = JSON.stringify(block.input, null, 2); }
209	        catch { pre.textContent = String(block.input); }
210	        d.appendChild(pre);
211	        toolUseById.set(block.id, { name: block.name, el: d });
212	        appendFrame(d);
213	      }
214	
215	      function renderToolResult(block) {
216	        const div = document.createElement('div');
217	        div.className = 'frame tool-result';
218	        const pre = document.createElement('pre');
219	        let text;
220	        if (typeof block.content === 'string') text = block.content;
221	        else if (Array.isArray(block.content)) {
222	          text = block.content.map(c => typeof c === 'string' ? c : (c.text || JSON.stringify(c))).join('\n');
223	        } else text = JSON.stringify(block.content || '');
224	        pre.textContent = text;
225	        div.appendChild(pre);
226	        if (text.length > 800) {
227	          const more = document.createElement('span');
228	          more.className = 'show-more';
229	          more.textContent = 'show more';
230	          more.addEventListener('click', () => {
231	            div.classList.toggle('expanded');
232	            more.textContent = div.classList.contains('expanded') ? 'show less' : 'show more';
233	          });
234	          div.appendChild(more);
235	        }
236	        appendFrame(div);
237	      }
238	
239	      function renderBoundary(frame) {
240	        const div = document.createElement('div');
241	        div.className = 'frame boundary ' + (frame.state || '');
242	        const label = document.createElement('span');
243	        label.className = 'label';
244	        label.textContent = '▸ task ' + (frame.state || '?');
245	        div.appendChild(label);
246	        const meta = document.createElement('span');
247	        meta.className = 'meta';
248	        const bits = [];
249	        if (frame.taskId) bits.push('id=' + frame.taskId);
250	        if (frame.domain) bits.push('domain=' + frame.domain);
251	        if (frame.wave != null) bits.push('wave=' + frame.wave);
252	        if (frame.exitCode != null) bits.push('exit=' + frame.exitCode);
253	        if (frame.durationMs != null) bits.push('duration=' + Math.round(frame.durationMs/1000) + 's');
254	        meta.textContent = bits.join('  ');
255	        div.appendChild(meta);
256	        appendFrame(div);
257	      }
258	
259	      function renderRaw(line) {
260	        const div = document.createElement('div');
261	        div.className = 'frame raw';
262	        div.textContent = line;
263	        appendFrame(div);
264	      }
265	
266	      function renderFrame(frame) {
267	        if (!frame || typeof frame !== 'object') return;
268	        const type = frame.type;
269	        if (type === 'system') { renderSystem(frame); return; }
270	        if (type === 'task-boundary') { renderBoundary(frame); return; }
271	        if (type === 'raw') { renderRaw(frame.line || ''); return; }
272	        if (type === 'assistant' && frame.message && Array.isArray(frame.message.content)) {
273	          for (const b of frame.message.content) {
274	            if (b.type === 'text') renderAssistantText(b.text || '');
275	            else if (b.type === 'thinking') renderThinking(b.thinking || b.text || '');
276	            else if (b.type === 'tool_use') renderToolUse(b);
277	            else renderRaw(JSON.stringify(b));
278	          }
279	          return;
280	        }
281	        if (type === 'user' && frame.message && Array.isArray(frame.message.content)) {
282	          for (const b of frame.message.content) {
283	            if (b.type === 'tool_result') renderToolResult(b);
284	            else if (b.type === 'text') renderUserMessage(b.text || '');
285	            else renderRaw(JSON.stringify(b));
286	          }
287	          return;
288	        }
289	        if (type === 'user' && typeof frame.message === 'string') {
290	          renderUserMessage(frame.message);
291	          return;
292	        }
293	        if (type === 'result') {
294	          const d = document.createElement('div');
295	          d.className = 'frame system';
296	          d.textContent = 'result subtype=' + (frame.subtype || '?') + ' duration=' + (frame.duration_ms || 0) + 'ms';
297	          appendFrame(d);
298	          return;
299	        }
300	        renderRaw(JSON.stringify(frame));
301	      }
302	
303	      // ── Sidebar ─────────────────────────────────────────────────────────
304	      //
305	      // Poll /transcripts every 3s, build a parent-indented tree, render.
306	      // Exposed as window.__gsdtBuildTree for unit-testable tree-build logic.
307	
308	      function buildTree(spawns) {
309	        // Map spawnId → node, then link children to parents. Orphans float
310	        // to the root level.
311	        const byId = new Map();
312	        const roots = [];
313	        for (const s of spawns) byId.set(s.spawnId, { ...s, children: [] });
314	        for (const node of byId.values()) {
315	          if (node.parentId && byId.has(node.parentId)) {
316	            byId.get(node.parentId).children.push(node);
317	          } else {
318	            roots.push(node);
319	          }
320	        }
321	        // Sort each level newest-first
322	        const ts = (a, b) => (Date.parse(b.startedAt) || 0) - (Date.parse(a.startedAt) || 0);
323	        roots.sort(ts);
324	        for (const n of byId.values()) n.children.sort(ts);
325	        return roots;
326	      }
327	      window.__gsdtBuildTree = buildTree;
328	
329	      function statusClass(s) {
330	        if (s.status === 'running') return 'running';
331	        if (s.status === 'failed') return 'failed';
332	        if (s.status === 'stopped') return 'stopped';
333	        return '';
334	      }
335	
336	      function renderTree(roots) {
337	        const tree = document.getElementById('tree');
338	        tree.innerHTML = '';
339	        if (!roots.length) {
340	          const e = document.createElement('div');
341	          e.className = 'empty';
342	          e.textContent = 'No spawns yet.';
343	          tree.appendChild(e);
344	          return;
345	        }
346	        const currentId = (location.hash || '#').slice(1) || spawnId;
347	        function render(node, depth) {
348	          const el = document.createElement('div');
349	          el.className = 'node ' + statusClass(node);
350	          if (node.spawnId === currentId) el.classList.add('active');
351	          el.style.paddingLeft = (12 + depth * 14) + 'px';
352	          const dot = document.createElement('span'); dot.className = 'dot';
353	          const name = document.createElement('span'); name.className = 'name';
354	          name.textContent = (node.command || 'spawn') + ' · ' + node.spawnId.slice(-8);
355	          name.title = (node.description || node.spawnId) + '\n' + (node.startedAt || '');
356	          const kill = document.createElement('button');
357	          kill.className = 'kill';
358	          kill.textContent = 'kill';
359	          kill.disabled = node.status !== 'running' || !node.workerPid;
360	          kill.addEventListener('click', (ev) => {
361	            ev.stopPropagation();
362	            if (!confirm('SIGTERM spawn ' + node.spawnId + ' (pid ' + node.workerPid + ')?')) return;
363	            fetch('/transcript/' + encodeURIComponent(node.spawnId) + '/kill', { method: 'POST' })
364	              .then((r) => r.json())
365	              .then((j) => { kill.textContent = j.status || 'killed'; })
366	              .catch(() => { kill.textContent = 'err'; });
367	          });
368	          el.appendChild(dot); el.appendChild(name); el.appendChild(kill);
369	          el.addEventListener('click', () => {
370	            if (node.spawnId === currentId) return;
371	            location.hash = node.spawnId;
372	          });
373	          document.getElementById('tree').appendChild(el);
374	          for (const c of node.children) render(c, depth + 1);
375	        }
376	        for (const r of roots) render(r, 0);
377	      }
378	
379	      let pollTimer = null;
380	      function pollSpawns() {
381	        fetch('/transcripts')
382	          .then((r) => r.json())
383	          .then((j) => renderTree(buildTree(j.spawns || [])))
384	          .catch(() => { /* keep last render */ });
385	      }
386	
387	      // ── SSE connection (reconnectable on hash change) ───────────────────
388	
389	      let src = null;
390	      function connect(id) {
391	        if (src) { try { src.close(); } catch { /* gone */ } src = null; }
392	        stream.innerHTML = '';
393	        toolUseById.clear();
394	        autoScroll = true;
395	        jumpBtn.classList.remove('visible');
396	        document.getElementById('hdr-spawn-id').textContent = id;
397	        setStatus('', 'connecting…');
398	        src = new EventSource('/transcript/' + encodeURIComponent(id) + '/stream');
399	        src.onopen = () => setStatus('connected', 'live');
400	        src.onerror = () => setStatus('error', 'disconnected');
401	        src.onmessage = (ev) => {
402	          if (!ev.data) return;
403	          try { renderFrame(JSON.parse(ev.data)); }
404	          catch { renderRaw(ev.data); }
405	        };
406	      }
407	
408	      window.addEventListener('hashchange', () => {
409	        const id = (location.hash || '').slice(1);
410	        if (id) { connect(id); pollSpawns(); }
411	      });
412	
413	      const initialId = (location.hash || '').slice(1) || spawnId;
414	      if (!location.hash && spawnId) location.hash = spawnId;
415	      connect(initialId);
416	
417	      pollSpawns();
418	      pollTimer = setInterval(pollSpawns, 3000);
419	    })();
420	  </script>
