1	#!/usr/bin/env node
2	
3	/**
4	 * GSD-T Headless Auto-Spawn — Detached headless continuation
5	 *
6	 * When the runway estimator refuses a run (projected context ≥ stop band),
7	 * the caller invokes `autoSpawnHeadless()` to hand off to a detached child
8	 * process running `gsd-t headless {command} --log`. The interactive session
9	 * never blocks on the child (`child.unref()`), so the user retains their
10	 * terminal and can work on unrelated tasks. On child completion, a macOS
11	 * notification fires (T2). The interactive session surfaces the result via
12	 * a read-back banner on the next `gsd-t-resume` or `gsd-t-status` call (T4).
13	 *
14	 * Zero external dependencies (Node.js built-ins only).
15	 *
16	 * Contract: .gsd-t/contracts/headless-auto-spawn-contract.md v1.0.0
17	 * Consumers: commands/gsd-t-execute|wave|integrate|quick|debug.md (via runway
18	 *            estimator handoff), bin/runway-estimator.js (conceptual target).
19	 */
20	
21	const fs = require("fs");
22	const path = require("path");
23	const { spawn } = require("child_process");
24	const {
25	  acquireHandoffLock,
26	  releaseHandoffLock,
27	  // waitForLockRelease — NOT consumed here. The child-side wait is
28	  // performed by `commands/gsd-t-resume.md` Step 0 (wired in m36
29	  // watch-loop Task 4); it calls waitForLockRelease(projectDir,
30	  // sessionId) before reading the continue-here file.
31	} = require("./handoff-lock.cjs");
32	
33	// ── Constants ────────────────────────────────────────────────────────────────
34	
35	const SESSIONS_DIR_REL = path.join(".gsd-t", "headless-sessions");
36	const LOG_DIR_REL = ".gsd-t"; // headless-{id}.log lives directly in .gsd-t
37	
38	// ── Exports ──────────────────────────────────────────────────────────────────
39	
40	module.exports = {
41	  autoSpawnHeadless,
42	  makeSessionId,
43	  writeSessionFile,
44	  writeContinueHereFile,
45	  markSessionCompleted,
46	};
47	
48	// ── autoSpawnHeadless ────────────────────────────────────────────────────────
49	
50	/**
51	 * @param {{
52	 *   command: string,
53	 *   args?: string[],
54	 *   continue_from?: string,
55	 *   projectDir?: string,
56	 *   context?: object,
57	 *   sessionContext?: object,
58	 *   sessionId?: string,
59	 *   watch?: boolean,
60	 *   spawnType?: 'primary' | 'validation'
61	 * }} opts
62	 * @returns {{ id: string | null, pid: number | null, logPath: string | null, timestamp: string, mode: 'headless' | 'in-context' }}
63	 */
64	function autoSpawnHeadless(opts) {
65	  const command = opts.command;
66	  const args = opts.args || [];
67	  const continue_from = opts.continue_from || ".";
68	  const projectDir = opts.projectDir || process.cwd();
69	  const context = opts.context || opts.sessionContext || null;
70	  const watch = opts.watch === true;
71	  const spawnType = opts.spawnType || "primary";
72	
73	  if (!command || typeof command !== "string") {
74	    throw new Error("autoSpawnHeadless: `command` is required");
75	  }
76	  if (spawnType !== "primary" && spawnType !== "validation") {
77	    throw new Error(
78	      `autoSpawnHeadless: \`spawnType\` must be 'primary' or 'validation' (got ${JSON.stringify(spawnType)})`,
79	    );
80	  }
81	
82	  // Propagation rules (headless-default-contract §2):
83	  //   watch=true + primary    → signal in-context fallback (caller uses Task)
84	  //   watch=true + validation → warn on stderr; proceed headless
85	  //   watch=false             → headless (default behavior)
86	  if (watch && spawnType === "primary") {
87	    // M39 D2 — append watch-progress tree below banner (best-effort).
88	    // Banner here is the in-context-fallback signal printed by the caller;
89	    // we don't own it, so we only render the tree to stdout. Never throws.
90	    try {
91	      const wp = require("./watch-progress.js");
92	      const stateDir = path.join(projectDir, ".gsd-t", ".watch-state");
93	      const tree = wp.buildTree(stateDir);
94	      const rendered = wp.renderTree(tree, { currentAgent: null });
95	      if (rendered) {
96	        // eslint-disable-next-line no-console
97	        console.log(rendered);
98	      }
99	    } catch (_) {
100	      /* watch-progress is best-effort; never crash the watch */
101	    }
102	    return {
103	      id: null,
104	      pid: null,
105	      logPath: null,
106	      timestamp: new Date().toISOString(),
107	      mode: "in-context",
108	    };
109	  }
110	  if (watch && spawnType === "validation") {
111	    try {
112	      process.stderr.write(
113	        `[headless-default] --watch ignored for validation spawn type: ${spawnType}\n`,
114	      );
115	    } catch (_) {
116	      /* best effort */
117	    }
118	  }
119	
120	  const timestamp = new Date().toISOString();
121	  const id = makeSessionId(command, new Date());
122	  const logPath = path.join(projectDir, LOG_DIR_REL, `headless-${id}.log`);
123	
124	  ensureDir(path.join(projectDir, LOG_DIR_REL));
125	  ensureDir(path.join(projectDir, SESSIONS_DIR_REL));
126	
127	  // Handoff-lock gate (m36 gap-fix T2). Only engaged when the caller
128	  // supplies a `sessionId` — existing callers that do not pass one keep
129	  // the pre-m36 behavior unchanged. When engaged, the lock is held
130	  // across writeContinueHereFile + spawn so a child that is already
131	  // waiting via `waitForLockRelease()` (see commands/gsd-t-resume.md
132	  // Step 0, wired by m36 watch-loop T4) cannot read a half-written
133	  // continue-here file. See .gsd-t/contracts/headless-auto-spawn-contract.md
134	  // v1.0.0 (implementation-detail primitive; no contract bump).
135	  const lockSessionId = typeof opts.sessionId === "string" && opts.sessionId
136	    ? opts.sessionId
137	    : null;
138	  let lockHandle = null;
139	  if (lockSessionId) {
140	    lockHandle = acquireHandoffLock(projectDir, lockSessionId);
141	  }
142	
143	  let pid = 0;
144	  try {
145	    // Open log file descriptor before spawning — child writes directly.
146	    const logFd = fs.openSync(logPath, "a");
147	
148	    // Headless invocation: `node bin/gsd-t.js headless <command> [args] --log`
149	    // The `gsd-t` CLI entry point is bin/gsd-t.js relative to projectDir.
150	    const gsdtCli = path.join(projectDir, "bin", "gsd-t.js");
151	    const childArgs = [gsdtCli, "headless", stripGsdtPrefix(command), ...args, "--log"];
152	
153	    // Inject command/phase/trace/model into worker env so event-stream entries
154	    // (both the writer CLI and the heartbeat PostToolUse hook) are tagged in
155	    // the child's context (Fix 2, v3.12.12; trace/model/project-dir added
156	    // v3.12.14 to close the null-telemetry regression).
157	    //
158	    // GSD_T_PHASE defaults to "execute" for primary spawns.
159	    // GSD_T_TRACE_ID / GSD_T_MODEL are inherited from parent env if set;
160	    // parents (orchestrator, command files) should set them before spawning.
161	    // GSD_T_PROJECT_DIR gives the writer a stable target when the child cwd
162	    // drifts (e.g., temp dirs in subagents).
163	    const workerEnv = Object.assign({}, process.env, {
164	      GSD_T_COMMAND: command,
165	      GSD_T_PHASE: process.env.GSD_T_PHASE || "execute",
166	      GSD_T_PROJECT_DIR: process.env.GSD_T_PROJECT_DIR || projectDir,
167	    });
168	    if (process.env.GSD_T_TRACE_ID) {
169	      workerEnv.GSD_T_TRACE_ID = process.env.GSD_T_TRACE_ID;
170	    }
171	    if (process.env.GSD_T_MODEL) {
172	      workerEnv.GSD_T_MODEL = process.env.GSD_T_MODEL;
173	    }
174	    workerEnv.GSD_T_AGENT_ID = "headless-" + id;
175	    if (process.env.GSD_T_AGENT_ID) {
176	      workerEnv.GSD_T_PARENT_AGENT_ID = process.env.GSD_T_AGENT_ID;
177	    }
178	
179	    const child = spawn("node", childArgs, {
180	      cwd: projectDir,
181	      detached: true,
182	      stdio: ["ignore", logFd, logFd],
183	      env: workerEnv,
184	    });
185	
186	    child.unref();
187	    fs.closeSync(logFd);
188	
189	    pid = child.pid || 0;
190	
191	    writeSessionFile(projectDir, {
192	      id,
193	      pid,
194	      logPath: path.relative(projectDir, logPath),
195	      startTimestamp: timestamp,
196	      command,
197	      args,
198	      status: "running",
199	      continueFromPath: continue_from,
200	      surfaced: false,
201	    });
202	
203	    writeContinueHereFile(projectDir, id, context);
204	  } finally {
205	    // Release the lock AFTER the child is confirmed started and
206	    // handoff artifacts are on disk. The finally ensures a spawn
207	    // failure still frees the slot for a retry.
208	    if (lockHandle) {
209	      try {
210	        releaseHandoffLock(lockHandle);
211	      } catch (_) {
212	        /* idempotent best-effort */
213	      }
214	    }
215	  }
216	
217	  // T2 — install completion watcher. Non-blocking (setImmediate) so the
218	  // caller's return is not delayed. The watcher uses `child.on('exit')` on
219	  // a separately-spawned bridge process; here we defer to fs.watchFile for
220	  // a detached approach that survives even after the parent's `unref()`.
221	  installCompletionWatcher({ projectDir, id, logPath, pid, startTimestamp: timestamp });
222	
223	  return {
224	    id,
225	    pid,
226	    logPath: path.relative(projectDir, logPath),
227	    timestamp,
228	    mode: "headless",
229	  };
230	}
231	
232	// ── makeSessionId ────────────────────────────────────────────────────────────
233	
234	/**
235	 * @param {string} command
236	 * @param {Date} [now]
237	 * @returns {string} e.g., "gsd-t-execute-2026-04-15-01-23-45"
238	 */
239	function makeSessionId(command, now) {
240	  const d = now || new Date();
241	  const pad = (n) => String(n).padStart(2, "0");
242	  const date = `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
243	  const time = `${pad(d.getHours())}-${pad(d.getMinutes())}-${pad(d.getSeconds())}`;
244	  const base = stripGsdtPrefix(command) || command;
245	  return `gsd-t-${base}-${date}-${time}`;
246	}
247	
248	// ── writeSessionFile ─────────────────────────────────────────────────────────
249	
250	function writeSessionFile(projectDir, session) {
251	  const fp = path.join(projectDir, SESSIONS_DIR_REL, `${session.id}.json`);
252	  ensureDir(path.dirname(fp));
253	  fs.writeFileSync(fp, JSON.stringify(session, null, 2) + "\n");
254	  return fp;
255	}
256	
257	// ── writeContinueHereFile ────────────────────────────────────────────────────
258	
259	function writeContinueHereFile(projectDir, id, context) {
260	  const fp = path.join(projectDir, SESSIONS_DIR_REL, `${id}-context.json`);
261	  const payload = context || buildContextSnapshot(projectDir);
262	  fs.writeFileSync(fp, JSON.stringify(payload, null, 2) + "\n");
263	  return fp;
264	}
265	
266	function buildContextSnapshot(projectDir) {
267	  // Best-effort snapshot of current GSD-T state at handoff time.
268	  const snap = {
269	    capturedAt: new Date().toISOString(),
270	    progress: null,
271	    currentDomain: null,
272	    pendingTasks: [],
273	    lastDecisionLogEntry: null,
274	    currentWave: null,
275	  };
276	  try {
277	    const progressFp = path.join(projectDir, ".gsd-t", "progress.md");
278	    if (fs.existsSync(progressFp)) {
279	      const raw = fs.readFileSync(progressFp, "utf8");
280	      snap.progress = firstNLines(raw, 20);
281	      // Pull the last Decision Log entry (last non-empty bullet line).
282	      const lines = raw.split("\n");
283	      for (let i = lines.length - 1; i >= 0; i--) {
284	        const ln = lines[i].trim();
285	        if (ln.startsWith("- ")) {
286	          snap.lastDecisionLogEntry = ln;
287	          break;
288	        }
289	      }
290	    }
291	  } catch (_) {
292	    /* best-effort */
293	  }
294	  return snap;
295	}
296	
297	function firstNLines(s, n) {
298	  return s.split("\n").slice(0, n).join("\n");
299	}
300	
301	// ── markSessionCompleted ─────────────────────────────────────────────────────
302	
303	/**
304	 * T2 completion hook — updates the session file in place.
305	 * @param {string} projectDir
306	 * @param {string} id
307	 * @param {{ exitCode: number, endTimestamp?: string }} result
308	 */
309	function markSessionCompleted(projectDir, id, result) {
310	  const fp = path.join(projectDir, SESSIONS_DIR_REL, `${id}.json`);
311	  if (!fs.existsSync(fp)) return;
312	  try {
313	    const s = JSON.parse(fs.readFileSync(fp, "utf8"));
314	    s.status = "completed";
315	    s.exitCode = result.exitCode;
316	    s.endTimestamp = result.endTimestamp || new Date().toISOString();
317	    fs.writeFileSync(fp, JSON.stringify(s, null, 2) + "\n");
318	  } catch (_) {
319	    /* ignore */
320	  }
321	}
322	
323	// ── Completion watcher (T2) — macOS notification on exit ─────────────────────
324	
325	function installCompletionWatcher(opts) {
326	  const { projectDir, id, pid, startTimestamp } = opts;
327	  if (!pid || pid <= 0) return;
328	
329	  // Poll-based watcher. We can't hold a reference to the child (it's unref'd
330	  // and detached), so we poll `process.kill(pid, 0)` which throws if the
331	  // process is gone. This is cheap and survives across detachment.
332	  const POLL_MS = 2000;
333	  const MAX_WAIT_MS = 60 * 60 * 1000; // 1 hour safety cap
334	  const startMs = Date.now();
335	  const dtStart = new Date(startTimestamp).toLocaleString("sv-SE", { hour12: false }).slice(0, 16);
336	
337	  const timer = setInterval(() => {
338	    let alive = false;
339	    try {
340	      process.kill(pid, 0);
341	      alive = true;
342	    } catch (_) {
343	      alive = false;
344	    }
345	    if (!alive) {
346	      clearInterval(timer);
347	      // Exit code is unknown from a signal-based probe. Best-effort: read
348	      // the log's last lines to guess, otherwise default to 0.
349	      const exitCode = guessExitCodeFromLog(projectDir, id);
350	      const endTimestamp = new Date().toISOString();
351	      markSessionCompleted(projectDir, id, {
352	        exitCode,
353	        endTimestamp,
354	      });
355	      // Append token-log row (Fix 1, v3.12.12)
356	      const dtEnd = new Date(endTimestamp).toLocaleString("sv-SE", { hour12: false }).slice(0, 16);
357	      const durationS = Math.round((Date.now() - startMs) / 1000);
358	      appendTokenLog(projectDir, {
359	        dtStart,
360	        dtEnd,
361	        command: extractCommand(id),
362	        durationS,
363	        exitCode,
364	      });
365	      fireMacNotification({ id, command: extractCommand(id), startTimestamp });
366	    } else if (Date.now() - startMs > MAX_WAIT_MS) {
367	      clearInterval(timer);
368	    }
369	  }, POLL_MS);
370	
371	  // Let the timer not block the parent's exit.
372	  if (typeof timer.unref === "function") timer.unref();
373	}
374	
375	function guessExitCodeFromLog(projectDir, id) {
376	  try {
377	    const fp = path.join(projectDir, LOG_DIR_REL, `headless-${id}.log`);
378	    if (!fs.existsSync(fp)) return 0;
379	    const raw = fs.readFileSync(fp, "utf8");
380	    if (/exit code[: ]+(\d+)/i.test(raw)) {
381	      const m = raw.match(/exit code[: ]+(\d+)/i);
382	      return parseInt(m[1], 10);
383	    }
384	    return 0;
385	  } catch (_) {
386	    return 0;
387	  }
388	}
389	
390	function extractCommand(id) {
391	  // id format: gsd-t-{command}-{date}-{time}
392	  const m = id.match(/^gsd-t-(.+?)-\d{4}-\d{2}-\d{2}-\d{2}-\d{2}-\d{2}$/);
393	  return m ? m[1] : id;
394	}
395	
396	function fireMacNotification({ id, command }) {
397	  if (process.platform !== "darwin") return;
398	  try {
399	    const { spawn } = require("child_process");
400	    const msg = `GSD-T headless run complete: ${id}`;
401	    const script = `display notification "${msg}" with title "GSD-T" subtitle "${command}"`;
402	    const child = spawn("osascript", ["-e", script], {
403	      detached: true,
404	      stdio: "ignore",
405	    });
406	    child.unref();
407	  } catch (_) {
408	    /* graceful degradation */
409	  }
410	}
411	
412	// ── Token-Log Writer (Fix 1, v3.12.12) ───────────────────────────────────────
413	
414	const TOKEN_LOG_HEADER =
415	  "| Datetime-start | Datetime-end | Command | Step | Model | Duration(s) | Notes | Domain | Task | Ctx% |\n" +
416	  "|---|---|---|---|---|---|---|---|---|---|\n";
417	
418	/**
419	 * Append one row to {projectDir}/.gsd-t/token-log.md matching the schema used
420	 * by interactive command-file observability blocks.
421	 *
422	 * @param {string} projectDir
423	 * @param {{ dtStart: string, dtEnd: string, command: string, durationS: number, exitCode: number }} entry
424	 */
425	function appendTokenLog(projectDir, entry) {
426	  try {
427	    const logPath = path.join(projectDir, ".gsd-t", "token-log.md");
428	    const note = entry.exitCode === 0 ? "headless spawn: ok" : `headless spawn: exit ${entry.exitCode}`;
429	    // v3.12.14: prefer env-var model over the old hardcoded "unknown". The
430	    // parent session should have set GSD_T_MODEL before invoking spawn; fall
431	    // back to "unknown" if not (graceful).
432	    const model = process.env.GSD_T_MODEL || "unknown";
433	    const row =
434	      `| ${entry.dtStart} | ${entry.dtEnd} | ${entry.command} | headless | ${model} | ${entry.durationS}s | ${note} | - | - | unknown |\n`;
435	    if (!fs.existsSync(logPath)) {
436	      // Create with header
437	      ensureDir(path.dirname(logPath));
438	      fs.writeFileSync(logPath, `# GSD-T Token Log\n\n${TOKEN_LOG_HEADER}${row}`);
439	    } else {
440	      // Check if header row exists; if not prepend it (migration for files created before this fix)
441	      const existing = fs.readFileSync(logPath, "utf8");
442	      if (!existing.includes("| Datetime-start |")) {
443	        fs.writeFileSync(logPath, `# GSD-T Token Log\n\n${TOKEN_LOG_HEADER}${existing}${row}`);
444	      } else {
445	        fs.appendFileSync(logPath, row);
446	      }
447	    }
448	  } catch (_) {
449	    /* best-effort — never halt the completion watcher */
450	  }
451	}
452	
453	// ── Helpers ──────────────────────────────────────────────────────────────────
454	
455	function ensureDir(d) {
456	  if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true });
457	}
458	
459	function stripGsdtPrefix(command) {
460	  if (typeof command !== "string") return "";
461	  return command.replace(/^gsd-t-/, "");
462	}
