2	/**
3	 * GSD-T Transcript Tee (M42 D1)
4	 *
5	 * Captures raw stream-json frames from every unattended spawn to
6	 * `.gsd-t/transcripts/{spawn-id}.ndjson` + maintains a registry at
7	 * `.gsd-t/transcripts/.index.json` used by the dashboard sidebar.
8	 *
9	 * Zero external deps. Append-only. Does not parse the frames — that's the
10	 * renderer's job. One frame per line; lines that fail JSON parse are still
11	 * tee'd so nothing is silently dropped.
12	 *
13	 * Contracts:
14	 *   - .gsd-t/contracts/stream-json-sink-contract.md v1.1.0 (frame shape)
15	 */
16	
17	const fs = require('fs');
18	const path = require('path');
19	const crypto = require('crypto');
20	
21	const TRANSCRIPTS_DIRNAME = path.join('.gsd-t', 'transcripts');
22	const INDEX_FILENAME = '.index.json';
23	
24	function _transcriptsDir(projectDir) {
25	  return path.join(projectDir || '.', TRANSCRIPTS_DIRNAME);
26	}
27	
28	function _indexPath(projectDir) {
29	  return path.join(_transcriptsDir(projectDir), INDEX_FILENAME);
30	}
31	
32	function _ensureDir(p) {
33	  if (!fs.existsSync(p)) fs.mkdirSync(p, { recursive: true });
34	}
35	
36	/**
37	 * Allocate a hierarchical spawn-id. Shape: `{parent-prefix}-{short}` where
38	 * `short` is an 8-char hex from a random UUID. Root spawns get no prefix.
39	 *
40	 * @param {object} [opts]
41	 * @param {string|null} [opts.parentId]
42	 * @returns {string}
43	 */
44	function allocateSpawnId(opts) {
45	  const parentId = opts && opts.parentId ? String(opts.parentId) : null;
46	  const short = crypto.randomBytes(4).toString('hex');
47	  return parentId ? `${parentId}.${short}` : `s-${short}`;
48	}
49	
50	function _readIndex(projectDir) {
51	  const p = _indexPath(projectDir);
52	  if (!fs.existsSync(p)) return { spawns: [] };
53	  try {
54	    const raw = fs.readFileSync(p, 'utf8');
55	    const parsed = JSON.parse(raw);
56	    if (!parsed || typeof parsed !== 'object' || !Array.isArray(parsed.spawns)) return { spawns: [] };
57	    return parsed;
58	  } catch (_) {
59	    return { spawns: [] };
60	  }
61	}
62	
63	function _writeIndex(projectDir, idx) {
64	  const p = _indexPath(projectDir);
65	  _ensureDir(path.dirname(p));
66	  const tmp = p + '.tmp';
67	  fs.writeFileSync(tmp, JSON.stringify(idx, null, 2));
68	  fs.renameSync(tmp, p);
69	}
70	
71	/**
72	 * Register a new transcript + create the ndjson file.
73	 *
74	 * @param {object} opts
75	 * @param {string} opts.spawnId
76	 * @param {string} [opts.projectDir='.']
77	 * @param {object} [opts.meta]           { parentId?, command?, description?, workerPid?, model? }
78	 * @returns {{spawnId, transcriptPath, startedAt}}
79	 */
80	function openTranscript(opts) {
81	  if (!opts || !opts.spawnId) throw new Error('openTranscript: spawnId required');
82	  const projectDir = opts.projectDir || '.';
83	  const meta = opts.meta || {};
84	  const dir = _transcriptsDir(projectDir);
85	  _ensureDir(dir);
86	
87	  const transcriptPath = path.join(dir, `${opts.spawnId}.ndjson`);
88	  if (!fs.existsSync(transcriptPath)) {
89	    fs.writeFileSync(transcriptPath, '');
90	  }
91	
92	  const startedAt = new Date().toISOString();
93	  const entry = {
94	    spawnId: opts.spawnId,
95	    parentId: meta.parentId || null,
96	    command: meta.command || null,
97	    description: meta.description || null,
98	    model: meta.model || null,
99	    workerPid: meta.workerPid || null,
100	    startedAt,
101	    endedAt: null,
102	    status: 'running',
103	  };
104	
105	  const idx = _readIndex(projectDir);
106	  const existing = idx.spawns.findIndex((s) => s.spawnId === opts.spawnId);
107	  if (existing >= 0) {
108	    idx.spawns[existing] = { ...idx.spawns[existing], ...entry };
109	  } else {
110	    idx.spawns.push(entry);
111	  }
112	  _writeIndex(projectDir, idx);
113	
114	  return { spawnId: opts.spawnId, transcriptPath, startedAt };
115	}
116	
117	/**
118	 * Append a single frame (already JSON-serializable) to the transcript.
119	 * `frame` may be a parsed object OR a raw string line — strings are wrapped
120	 * as `{type:"raw",line}` so the ndjson shape stays uniform.
121	 *
122	 * @param {object} opts
123	 * @param {string} opts.spawnId
124	 * @param {string} [opts.projectDir='.']
125	 * @param {object|string} opts.frame
126	 */
127	function appendFrame(opts) {
128	  if (!opts || !opts.spawnId) throw new Error('appendFrame: spawnId required');
129	  if (opts.frame === undefined || opts.frame === null) return;
130	  const projectDir = opts.projectDir || '.';
131	  const p = path.join(_transcriptsDir(projectDir), `${opts.spawnId}.ndjson`);
132	  _ensureDir(path.dirname(p));
133	
134	  let line;
135	  if (typeof opts.frame === 'string') {
136	    const trimmed = opts.frame.trim();
137	    if (!trimmed) return;
138	    try {
139	      JSON.parse(trimmed);
140	      line = trimmed;
141	    } catch (_) {
142	      line = JSON.stringify({ type: 'raw', line: opts.frame });
143	    }
144	  } else {
145	    try {
146	      line = JSON.stringify(opts.frame);
147	    } catch (_) {
148	      line = JSON.stringify({ type: 'raw', line: String(opts.frame) });
149	    }
150	  }
151	  fs.appendFileSync(p, line + '\n');
152	}
153	
154	/**
155	 * Mark a transcript as ended. Idempotent — subsequent calls update endedAt.
156	 *
157	 * @param {object} opts
158	 * @param {string} opts.spawnId
159	 * @param {string} [opts.projectDir='.']
160	 * @param {'done'|'failed'|'stopped'|'ended'} [opts.status='ended']
161	 */
162	function closeTranscript(opts) {
163	  if (!opts || !opts.spawnId) throw new Error('closeTranscript: spawnId required');
164	  const projectDir = opts.projectDir || '.';
165	  const idx = _readIndex(projectDir);
166	  const i = idx.spawns.findIndex((s) => s.spawnId === opts.spawnId);
167	  if (i < 0) return false;
168	  idx.spawns[i].endedAt = new Date().toISOString();
169	  idx.spawns[i].status = opts.status || 'ended';
170	  _writeIndex(projectDir, idx);
171	  return true;
172	}
173	
174	/**
175	 * List registered spawns (most recent first).
176	 *
177	 * @param {string} [projectDir='.']
178	 * @returns {Array<object>}
179	 */
180	function listTranscripts(projectDir) {
181	  const idx = _readIndex(projectDir || '.');
182	  return idx.spawns.slice().sort((a, b) => {
183	    const ta = Date.parse(a.startedAt) || 0;
184	    const tb = Date.parse(b.startedAt) || 0;
185	    return tb - ta;
186	  });
187	}
188	
189	function readTranscriptMeta(projectDir, spawnId) {
190	  const idx = _readIndex(projectDir || '.');
191	  return idx.spawns.find((s) => s.spawnId === spawnId) || null;
192	}
193	
194	/**
195	 * Tee a stream-json stdout stream. Returns an `onChunk(buffer)` callback that
196	 * you feed chunks to (typed as Buffer or string). Frames are split at `\n`
197	 * and each complete line is written to the transcript ndjson. Incomplete
198	 * tails are buffered until the next chunk.
199	 *
200	 * Returns also a `flush()` to call on child exit — writes any stranded tail
201	 * as a single `{type:"raw"}` line so nothing is dropped.
202	 *
203	 * @param {object} opts
204	 * @param {string} opts.spawnId
205	 * @param {string} [opts.projectDir='.']
206	 * @returns {{onChunk: (chunk) => void, flush: () => void}}
207	 */
208	function makeStreamTee(opts) {
209	  if (!opts || !opts.spawnId) throw new Error('makeStreamTee: spawnId required');
210	  const projectDir = opts.projectDir || '.';
211	  const spawnId = opts.spawnId;
212	  let buf = '';
213	
214	  return {
215	    onChunk(chunk) {
216	      if (chunk == null) return;
217	      buf += Buffer.isBuffer(chunk) ? chunk.toString('utf8') : String(chunk);
218	      let nl;
219	      while ((nl = buf.indexOf('\n')) >= 0) {
220	        const line = buf.slice(0, nl);
221	        buf = buf.slice(nl + 1);
222	        if (line.length > 0) appendFrame({ spawnId, projectDir, frame: line });
223	      }
224	    },
225	    flush() {
226	      if (buf.length > 0) {
227	        appendFrame({ spawnId, projectDir, frame: buf });
228	        buf = '';
229	      }
230	    },
231	  };
232	}
233	
234	module.exports = {
235	  allocateSpawnId,
236	  openTranscript,
237	  appendFrame,
238	  closeTranscript,
239	  listTranscripts,
240	  readTranscriptMeta,
241	  makeStreamTee,
242	  _readIndex,
243	  _writeIndex,
244	  TRANSCRIPTS_DIRNAME,
245	  INDEX_FILENAME,
246	};
