22	function buildTree(spawns) {
23	  const byId = new Map();
24	  const roots = [];
25	  for (const s of spawns) byId.set(s.spawnId, { ...s, children: [] });
26	  for (const node of byId.values()) {
27	    if (node.parentId && byId.has(node.parentId)) {
28	      byId.get(node.parentId).children.push(node);
29	    } else {
30	      roots.push(node);
31	    }
32	  }
33	  const ts = (a, b) => (Date.parse(b.startedAt) || 0) - (Date.parse(a.startedAt) || 0);
34	  roots.sort(ts);
35	  for (const n of byId.values()) n.children.sort(ts);
36	  return roots;
37	}
