    const dir = mkTmp();
    writeUsageJsonl(dir, [
      { spawn_id: 's-x', turn_id: 't1', inputTokens: 10, outputTokens: 100 },
      { spawn_id: 's-x', turn_id: 't2', inputTokens: 20, outputTokens: 200 },
