let pollTimer = null;
function pollSpawns() {
  fetch('/transcripts')
    .then((r) => r.json())
    .then((j) => {
      const spawns = j.spawns || [];
      renderTree(buildTree(spawns));
      maybeAutoFollow(spawns);
