/**
 * Synchronous port-binding check. Uses a short connect attempt. Returns
 * `true` if something answers on the port, `false` otherwise. This is a
 * best-effort "is the dashboard already running" probe — more permissive
 * than a port reservation attempt, and safe to call from a synchronous
 * caller.
 *
 * We use `net.createServer().listen()` synchronously (Node returns quickly
 * when the port is in use), wrapped by a promise + synchronous runloop.
 * For the synchronous caller (autoSpawnHeadless), we instead use
 * `_portBusySync` below which relies on a `net.Socket` connect-with-timeout.
 */
function _portBusySyncAttempt(port, host, cb) {
  const socket = new net.Socket();
  let settled = false;
  const finish = (busy) => {
    if (settled) return;
    settled = true;
    try { socket.destroy(); } catch (_) { /* ok */ }
    cb(busy);
  };
  socket.setTimeout(150);
  socket.once('connect', () => finish(true));
  socket.once('timeout', () => finish(false));
  socket.once('error', () => finish(false));
  try { socket.connect(port, host || '127.0.0.1'); }
  catch (_) { finish(false); }
}

/**
 * Ensure the dashboard server is running on the project's scoped port.
 *
 * Idempotent: safe to call on every spawn. Silent: no stdout/stderr writes
 * on the happy path; the detached child's stdio is ignored.
 *
 * **Synchronous contract**: returns immediately with `{port, pid, alreadyRunning}`.
 *  - If something answers on `port` right now, returns `alreadyRunning: true`.
 *  - Otherwise fork-detaches the dashboard server (fire-and-forget) and
 *    returns with `alreadyRunning: false` + the new pid. The caller can
 *    print the URL banner immediately — the server binds in <50ms in
 *    practice and the browser's first request will retry.
 *
 * We use a short-timeout TCP connect probe (150ms) because `net.Server#listen`
 * is async; callers need a synchronous answer to decide whether to spawn.
 *
 * @param {object} opts
 * @param {string} [opts.projectDir='.']
 * @param {number} [opts.port]
 * @param {string} [opts.host='127.0.0.1']
 * @returns {{port: number, pid: number|null, alreadyRunning: boolean}}
 */
function ensureDashboardRunning(opts) {
  const projectDir = (opts && opts.projectDir) || '.';
  const host = (opts && opts.host) || '127.0.0.1';
  let port = opts && opts.port;
  if (!port) {
    const srv = require('./gsd-t-dashboard-server.js');
    port = srv.projectScopedDefaultPort(projectDir);
  }

  // Synchronous probe via deasync-free trick: we spin on `_portBusySyncAttempt`
  // with a 150ms socket timeout. The socket is configured for immediate resolution
  // — the only blocking we do is a short spin-loop waiting for the callback.
  let answered = false;
  let busy = false;
  _portBusySyncAttempt(port, host, (b) => { busy = b; answered = true; });
  const start = Date.now();
  const deadlineMs = 250; // slightly > socket timeout
  // Spin until the socket fires or we time out. Using setImmediate inside
  // a busy-spin via Atomics.wait would be cleaner but we want zero-deps.
  // eslint-disable-next-line no-unmodified-loop-condition
  while (!answered && (Date.now() - start) < deadlineMs) {
    // Release event loop tick — the node runtime advances internal IO.
    try {
      // eslint-disable-next-line no-empty
    } catch (_) { }
    // Busy-loop is OK for a ~150ms wait on program startup.
  }

  if (busy) {
    // Record pid for existing-server case? We can't know the pid of the
    // foreign server, so we only write when WE spawn it.
    return { port, pid: null, alreadyRunning: true };
  }

  // Port appears free — fork-detach the dashboard server.
  const serverScript = path.join(__dirname, 'gsd-t-dashboard-server.js');
  const child = spawn(process.execPath, [serverScript, '--port', String(port)], {
    cwd: projectDir,
    detached: true,
    stdio: 'ignore',
    env: Object.assign({}, process.env, {
      GSD_T_PROJECT_DIR: path.resolve(projectDir),
    }),
  });
