'use strict';
/**
 * M43 D2-T7 — performance gate.
 *
 * Synthesizes 30k events + 3k turns, asserts that
 * joinTurnsAndEvents + aggregateByTool completes in < 3s on a dev laptop.
 */

const test = require('node:test');
const assert = require('node:assert/strict');
const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');
const { performance } = require('node:perf_hooks');

const {
  joinTurnsAndEvents,
  aggregateByTool,
} = require('../bin/gsd-t-tool-attribution.cjs');

function writeJsonl(p, rows) {
  fs.mkdirSync(path.dirname(p), { recursive: true });
  fs.writeFileSync(p, rows.map((r) => JSON.stringify(r)).join('\n') + '\n');
}

test('perf gate: 3k turns × 30k events — join + aggregate in < 3s', () => {
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'gsd-t-m43-d2-perf-'));
  try {
    const turns = [];
    const events = [];
    const tools = ['Bash', 'Read', 'Edit', 'Grep', 'Task', 'WebFetch', 'Glob', 'Write', 'ToolSearch'];
    const sessions = 30; // 3000 turns / 30 sessions = 100 turns per session
    const turnsPerSession = 100;
    const eventsPerTurn = 10; // 30000 events total
    const baseMs = Date.parse('2026-04-21T00:00:00.000Z');

    for (let s = 0; s < sessions; s++) {
      const sid = `sess-${s}`;
      for (let t = 0; t < turnsPerSession; t++) {
        const turnMs = baseMs + ((s * turnsPerSession + t) * 60_000); // 1 minute apart
        const iso = new Date(turnMs).toISOString();
        turns.push({
          schemaVersion: 2,
          ts: iso,
          source: 'live',
          command: 'in-session',
          step: 'turn',
          model: 'sonnet',
          startedAt: iso.slice(0, 16).replace('T', ' '),
          endedAt:   iso.slice(0, 16).replace('T', ' '),
          durationMs: 0,
          inputTokens: 10,
          outputTokens: 100,
          cacheReadInputTokens: 5000,
          cacheCreationInputTokens: 200,
          costUSD: 0.01,
          domain: (s % 2 === 0) ? 'auth' : 'payments',
          task: null,
          milestone: 'M43',
          ctxPct: null,
          notes: null,
          hasUsage: true,
          session_id: sid,
          turn_id: `t-${t}`,
          sessionType: 'in-session',
        });
        for (let e = 0; e < eventsPerTurn; e++) {
          const evMs = turnMs + 1000 + (e * 500); // after turn, before next
          events.push({
            ts: new Date(evMs).toISOString(),
            event_type: 'tool_call',
            command: null,
            phase: null,
            trace_id: null,
            agent_id: sid,
            parent_agent_id: null,
            reasoning: tools[(s + t + e) % tools.length],
            outcome: null,
          });
        }
      }
    }
    assert.equal(turns.length, 3000);
    assert.equal(events.length, 30000);

    const turnsPath  = path.join(dir, '.gsd-t', 'metrics', 'token-usage.jsonl');
    const eventsPath = path.join(dir, '.gsd-t', 'events', '2026-04-21.jsonl');
    writeJsonl(turnsPath, turns);
    writeJsonl(eventsPath, events);

    const t0 = performance.now();
    const joined = joinTurnsAndEvents({
      turnsPath,
      eventsGlob: path.join(dir, '.gsd-t', 'events'),
    });
    const agg = aggregateByTool(joined);
    const t1 = performance.now();
    const elapsed = t1 - t0;

    // Functional assertions.
    assert.equal(joined.length, 3000);
    assert.ok(agg.length >= 2, `expected multiple tool keys, got ${agg.length}`);

    // Perf assertion.
    assert.ok(elapsed < 3000, `perf gate failed: ${elapsed.toFixed(0)}ms > 3000ms`);

    // Sanity: log wall-clock (helpful when gate drifts in CI).
    process.stdout.write(`[perf-gate] 3k turns × 30k events joined+aggregated in ${elapsed.toFixed(0)}ms\n`);
  } finally {
    try { fs.rmSync(dir, { recursive: true, force: true }); } catch (_) {}
  }
});

'use strict';
/**
 * M43 D6-T4 — dashboard autostart: port probe → fork-detach → pid file.
 *
 * Tests:
 *   1. Port already bound → no-op, returns alreadyRunning:true, pid:null.
 *   2. Port free → spawns detached server, writes pid file, returns pid.
 *   3. Idempotent — back-to-back calls don't double-spawn.
 *
 * We use ephemeral ports (net.createServer then read `.address().port`)
 * to avoid collisions with other tests or a live project dashboard.
 */

const test = require('node:test');
const assert = require('node:assert/strict');
const fs = require('fs');
const net = require('net');
const os = require('os');
const path = require('path');

const autostart = require('../scripts/gsd-t-dashboard-autostart.cjs');

function mkTmp() {
  return fs.mkdtempSync(path.join(os.tmpdir(), 'gsd-t-m43-autostart-'));
}

function reserveEphemeralPort() {
  return new Promise((resolve, reject) => {
    const srv = net.createServer();
    srv.once('error', reject);
    srv.listen(0, '127.0.0.1', () => {
      const port = srv.address().port;
      resolve({ srv, port });
    });
  });
}

test('_isPortBusySync — returns false for unbound port', () => {
  // Port well above ephemeral range — highly unlikely to be in use.
  const busy = autostart._isPortBusySync(48211, '127.0.0.1');
  assert.equal(busy, false);
});

test('_isPortBusySync — returns true when the port is already bound', async () => {
  const { srv, port } = await reserveEphemeralPort();
  try {
    const busy = autostart._isPortBusySync(port, '127.0.0.1');
    assert.equal(busy, true, `expected port ${port} to register as busy`);
  } finally {
    await new Promise((r) => srv.close(r));
  }
});

test('ensureDashboardRunning — port already bound returns alreadyRunning:true', async () => {
  const { srv, port } = await reserveEphemeralPort();
  const dir = mkTmp();
  try {
    const result = autostart.ensureDashboardRunning({ projectDir: dir, port });
    assert.equal(result.port, port);
    assert.equal(result.alreadyRunning, true);
    assert.equal(result.pid, null);
    // No pid file written when we didn't spawn
    const pidFile = path.join(dir, '.gsd-t', '.dashboard.pid');
    assert.equal(fs.existsSync(pidFile), false);
  } finally {
    await new Promise((r) => srv.close(r));
  }
});

test('ensureDashboardRunning — port free, spawns and writes pid file', async () => {
  const dir = mkTmp();
  // Pick a high port unlikely to clash
  const port = 19000 + Math.floor(Math.random() * 800);
  const result = autostart.ensureDashboardRunning({ projectDir: dir, port });
  try {
    assert.equal(result.port, port);
    assert.equal(result.alreadyRunning, false);
    assert.ok(result.pid && typeof result.pid === 'number', `expected numeric pid, got ${result.pid}`);

    // Pid file landed
    const pidFile = path.join(dir, '.gsd-t', '.dashboard.pid');
    assert.equal(fs.existsSync(pidFile), true, 'pid file should exist');
    assert.equal(fs.readFileSync(pidFile, 'utf8').trim(), String(result.pid));

    // Give the child a moment to bind
    await new Promise((r) => setTimeout(r, 400));

    // Second call should detect busy and no-op
    const again = autostart.ensureDashboardRunning({ projectDir: dir, port });
    assert.equal(again.alreadyRunning, true, 'second call should see busy port');
    assert.equal(again.pid, null);
  } finally {
    if (result.pid) { try { process.kill(result.pid, 'SIGTERM'); } catch (_) { /* gone */ } }
  }
});

test('ensureDashboardRunning — idempotent back-to-back (second call skips spawn)', async () => {
  const dir = mkTmp();
  const port = 19900 + Math.floor(Math.random() * 90);
  const first = autostart.ensureDashboardRunning({ projectDir: dir, port });
  try {
    assert.equal(first.alreadyRunning, false);
    // give child time to bind
    await new Promise((r) => setTimeout(r, 400));
    const second = autostart.ensureDashboardRunning({ projectDir: dir, port });
    assert.equal(second.alreadyRunning, true);
    assert.equal(second.pid, null);
  } finally {
    if (first.pid) { try { process.kill(first.pid, 'SIGTERM'); } catch (_) { /* gone */ } }
  }
});

test('ensureDashboardRunning — _pidPath uses .gsd-t/.dashboard.pid', () => {
  const p = autostart._pidPath('/tmp/foo');
  assert.equal(p, path.join('/tmp/foo', '.gsd-t', '.dashboard.pid'));
});

