  const deadline = Date.now() + (timeoutMs || 3000);
  while (Date.now() < deadline) {
    if (autostart._isPortBusySync(port, '127.0.0.1')) return true;
    await new Promise((r) => setTimeout(r, 100));
  }
  return false;
}

