113	        `[headless-default] --watch ignored for validation spawn type: ${spawnType}\n`,
114	      );
115	    } catch (_) {
116	      /* best effort */
117	    }
118	  }
119	
120	  const timestamp = new Date().toISOString();
121	  const id = makeSessionId(command, new Date());
122	  const logPath = path.join(projectDir, LOG_DIR_REL, `headless-${id}.log`);
123	
124	  ensureDir(path.join(projectDir, LOG_DIR_REL));
125	  ensureDir(path.join(projectDir, SESSIONS_DIR_REL));
126	
127	  // M43 D6-T4 — Ensure dashboard is running (idempotent; no-op if already up).
128	  // Must happen BEFORE the URL banner print (D6-T3) so the link is live.
129	  // Never throws — autostart is best-effort.
130	  let autostartInfo = null;
131	  try {
132	    const { ensureDashboardRunning } = require("../scripts/gsd-t-dashboard-autostart.cjs");
133	    autostartInfo = ensureDashboardRunning({ projectDir });
134	  } catch (_) {
135	    /* best-effort; fall through without banner port info */
136	  }
137	
138	  // M43 D6-T3 — Live transcript URL banner. Printed for every spawn so the
139	  // viewer at :PORT is "the" primary watching surface. Never throws.
140	  // Text is coordinated with D4 — exact line shape is part of
141	  // dashboard-server-contract.md §Banner Format.
142	  try {
143	    let port = autostartInfo && autostartInfo.port;
144	    if (!port) {
145	      const { projectScopedDefaultPort } = require("../scripts/gsd-t-dashboard-server.js");
146	      port = projectScopedDefaultPort(projectDir);
147	    }
148	    process.stdout.write(`▶ Live transcript: http://127.0.0.1:${port}/transcript/${id}\n`);
149	  } catch (_) {
150	    /* best-effort — never crash the spawn on banner failure */
151	  }
152	
153	  // Handoff-lock gate (m36 gap-fix T2). Only engaged when the caller
154	  // supplies a `sessionId` — existing callers that do not pass one keep
155	  // the pre-m36 behavior unchanged. When engaged, the lock is held
156	  // across writeContinueHereFile + spawn so a child that is already
157	  // waiting via `waitForLockRelease()` (see commands/gsd-t-resume.md
158	  // Step 0, wired by m36 watch-loop T4) cannot read a half-written
159	  // continue-here file. See .gsd-t/contracts/headless-auto-spawn-contract.md
160	  // v1.0.0 (implementation-detail primitive; no contract bump).
161	  const lockSessionId = typeof opts.sessionId === "string" && opts.sessionId
162	    ? opts.sessionId
163	    : null;
164	  let lockHandle = null;
165	  if (lockSessionId) {
166	    lockHandle = acquireHandoffLock(projectDir, lockSessionId);
167	  }
168	
169	  let pid = 0;
170	  try {
171	    // Open log file descriptor before spawning — child writes directly.
172	    const logFd = fs.openSync(logPath, "a");
173	
174	    // Headless invocation: `node bin/gsd-t.js headless <command> [args] --log`
175	    // The `gsd-t` CLI entry point is bin/gsd-t.js relative to projectDir.
176	    const gsdtCli = path.join(projectDir, "bin", "gsd-t.js");
177	    const childArgs = [gsdtCli, "headless", stripGsdtPrefix(command), ...args, "--log"];
178	
179	    // Inject command/phase/trace/model into worker env so event-stream entries
180	    // (both the writer CLI and the heartbeat PostToolUse hook) are tagged in
181	    // the child's context (Fix 2, v3.12.12; trace/model/project-dir added
182	    // v3.12.14 to close the null-telemetry regression).
183	    //
184	    // GSD_T_PHASE defaults to "execute" for primary spawns.
185	    // GSD_T_TRACE_ID / GSD_T_MODEL are inherited from parent env if set;
186	    // parents (orchestrator, command files) should set them before spawning.
187	    // GSD_T_PROJECT_DIR gives the writer a stable target when the child cwd
188	    // drifts (e.g., temp dirs in subagents).
189	    const workerEnv = Object.assign({}, process.env, {
190	      GSD_T_COMMAND: command,
191	      GSD_T_PHASE: process.env.GSD_T_PHASE || "execute",
192	      GSD_T_PROJECT_DIR: process.env.GSD_T_PROJECT_DIR || projectDir,
193	    });
194	    if (process.env.GSD_T_TRACE_ID) {
195	      workerEnv.GSD_T_TRACE_ID = process.env.GSD_T_TRACE_ID;
196	    }
197	    if (process.env.GSD_T_MODEL) {
198	      workerEnv.GSD_T_MODEL = process.env.GSD_T_MODEL;
199	    }
200	    workerEnv.GSD_T_AGENT_ID = "headless-" + id;
201	    if (process.env.GSD_T_AGENT_ID) {
202	      workerEnv.GSD_T_PARENT_AGENT_ID = process.env.GSD_T_AGENT_ID;
203	    }
204	
205	    const child = spawn("node", childArgs, {
206	      cwd: projectDir,
207	      detached: true,
208	      stdio: ["ignore", logFd, logFd],
209	      env: workerEnv,
210	    });
211	
212	    child.unref();
213	    fs.closeSync(logFd);
214	
215	    pid = child.pid || 0;
216	
217	    writeSessionFile(projectDir, {
218	      id,
219	      pid,
220	      logPath: path.relative(projectDir, logPath),
221	      startTimestamp: timestamp,
222	      command,
223	      args,
224	      status: "running",
225	      continueFromPath: continue_from,
226	      surfaced: false,
227	    });
228	
229	    writeContinueHereFile(projectDir, id, context);
230	  } finally {
231	    // Release the lock AFTER the child is confirmed started and
232	    // handoff artifacts are on disk. The finally ensures a spawn
233	    // failure still frees the slot for a retry.
234	    if (lockHandle) {
235	      try {
236	        releaseHandoffLock(lockHandle);
237	      } catch (_) {
238	        /* idempotent best-effort */
239	      }
240	    }
241	  }
242	
243	  // T2 — install completion watcher. Non-blocking (setImmediate) so the
244	  // caller's return is not delayed. The watcher uses `child.on('exit')` on
245	  // a separately-spawned bridge process; here we defer to fs.watchFile for
246	  // a detached approach that survives even after the parent's `unref()`.
247	  installCompletionWatcher({ projectDir, id, logPath, pid, startTimestamp: timestamp });
248	
249	  return {
250	    id,
251	    pid,
252	    logPath: path.relative(projectDir, logPath),
253	    timestamp,
254	    mode: "headless",
255	  };
256	}
