258	// ── makeSessionId ────────────────────────────────────────────────────────────
259	
260	/**
261	 * @param {string} command
262	 * @param {Date} [now]
263	 * @returns {string} e.g., "gsd-t-execute-2026-04-15-01-23-45"
264	 */
265	function makeSessionId(command, now) {
266	  const d = now || new Date();
267	  const pad = (n) => String(n).padStart(2, "0");
268	  const date = `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
269	  const time = `${pad(d.getHours())}-${pad(d.getMinutes())}-${pad(d.getSeconds())}`;
270	  const base = stripGsdtPrefix(command) || command;
271	  return `gsd-t-${base}-${date}-${time}`;
272	}
