274	// ── writeSessionFile ─────────────────────────────────────────────────────────
275	
276	function writeSessionFile(projectDir, session) {
277	  const fp = path.join(projectDir, SESSIONS_DIR_REL, `${session.id}.json`);
278	  ensureDir(path.dirname(fp));
279	  fs.writeFileSync(fp, JSON.stringify(session, null, 2) + "\n");
280	  return fp;
281	}
