283	// ── writeContinueHereFile ────────────────────────────────────────────────────
284	
285	function writeContinueHereFile(projectDir, id, context) {
286	  const fp = path.join(projectDir, SESSIONS_DIR_REL, `${id}-context.json`);
287	  const payload = context || buildContextSnapshot(projectDir);
288	  fs.writeFileSync(fp, JSON.stringify(payload, null, 2) + "\n");
289	  return fp;
290	}
291	
292	function buildContextSnapshot(projectDir) {
293	  // Best-effort snapshot of current GSD-T state at handoff time.
294	  const snap = {
295	    capturedAt: new Date().toISOString(),
296	    progress: null,
297	    currentDomain: null,
298	    pendingTasks: [],
299	    lastDecisionLogEntry: null,
300	    currentWave: null,
301	  };
302	  try {
303	    const progressFp = path.join(projectDir, ".gsd-t", "progress.md");
304	    if (fs.existsSync(progressFp)) {
305	      const raw = fs.readFileSync(progressFp, "utf8");
306	      snap.progress = firstNLines(raw, 20);
307	      // Pull the last Decision Log entry (last non-empty bullet line).
308	      const lines = raw.split("\n");
309	      for (let i = lines.length - 1; i >= 0; i--) {
310	        const ln = lines[i].trim();
311	        if (ln.startsWith("- ")) {
312	          snap.lastDecisionLogEntry = ln;
313	          break;
314	        }
315	      }
316	    }
317	  } catch (_) {
318	    /* best-effort */
319	  }
320	  return snap;
321	}
322	
323	function firstNLines(s, n) {
324	  return s.split("\n").slice(0, n).join("\n");
325	}
