327	// ── markSessionCompleted ─────────────────────────────────────────────────────
328	
329	/**
330	 * T2 completion hook — updates the session file in place.
331	 * @param {string} projectDir
332	 * @param {string} id
333	 * @param {{ exitCode: number, endTimestamp?: string }} result
334	 */
335	function markSessionCompleted(projectDir, id, result) {
336	  const fp = path.join(projectDir, SESSIONS_DIR_REL, `${id}.json`);
337	  if (!fs.existsSync(fp)) return;
338	  try {
339	    const s = JSON.parse(fs.readFileSync(fp, "utf8"));
340	    s.status = "completed";
341	    s.exitCode = result.exitCode;
342	    s.endTimestamp = result.endTimestamp || new Date().toISOString();
343	    fs.writeFileSync(fp, JSON.stringify(s, null, 2) + "\n");
344	  } catch (_) {
345	    /* ignore */
346	  }
347	}
348	
349	// ── Completion watcher (T2) — macOS notification on exit ─────────────────────
350	
351	function installCompletionWatcher(opts) {
352	  const { projectDir, id, pid, startTimestamp } = opts;
353	  if (!pid || pid <= 0) return;
354	
355	  // Poll-based watcher. We can't hold a reference to the child (it's unref'd
356	  // and detached), so we poll `process.kill(pid, 0)` which throws if the
357	  // process is gone. This is cheap and survives across detachment.
358	  const POLL_MS = 2000;
359	  const MAX_WAIT_MS = 60 * 60 * 1000; // 1 hour safety cap
360	  const startMs = Date.now();
361	  const dtStart = new Date(startTimestamp).toLocaleString("sv-SE", { hour12: false }).slice(0, 16);
362	
363	  const timer = setInterval(() => {
364	    let alive = false;
365	    try {
366	      process.kill(pid, 0);
367	      alive = true;
368	    } catch (_) {
369	      alive = false;
370	    }
371	    if (!alive) {
372	      clearInterval(timer);
373	      // Exit code is unknown from a signal-based probe. Best-effort: read
374	      // the log's last lines to guess, otherwise default to 0.
375	      const exitCode = guessExitCodeFromLog(projectDir, id);
376	      const endTimestamp = new Date().toISOString();
377	      markSessionCompleted(projectDir, id, {
378	        exitCode,
379	        endTimestamp,
380	      });
381	      // Append token-log row (Fix 1, v3.12.12)
382	      const dtEnd = new Date(endTimestamp).toLocaleString("sv-SE", { hour12: false }).slice(0, 16);
383	      const durationS = Math.round((Date.now() - startMs) / 1000);
384	      appendTokenLog(projectDir, {
385	        dtStart,
386	        dtEnd,
387	        command: extractCommand(id),
388	        durationS,
389	        exitCode,
390	      });
391	      fireMacNotification({ id, command: extractCommand(id), startTimestamp });
392	    } else if (Date.now() - startMs > MAX_WAIT_MS) {
393	      clearInterval(timer);
394	    }
395	  }, POLL_MS);
396	
397	  // Let the timer not block the parent's exit.
398	  if (typeof timer.unref === "function") timer.unref();
399	}
400	
401	function guessExitCodeFromLog(projectDir, id) {
402	  try {
403	    const fp = path.join(projectDir, LOG_DIR_REL, `headless-${id}.log`);
404	    if (!fs.existsSync(fp)) return 0;
405	    const raw = fs.readFileSync(fp, "utf8");
406	    if (/exit code[: ]+(\d+)/i.test(raw)) {
407	      const m = raw.match(/exit code[: ]+(\d+)/i);
408	      return parseInt(m[1], 10);
409	    }
410	    return 0;
411	  } catch (_) {
412	    return 0;
413	  }
414	}
415	
416	function extractCommand(id) {
417	  // id format: gsd-t-{command}-{date}-{time}
418	  const m = id.match(/^gsd-t-(.+?)-\d{4}-\d{2}-\d{2}-\d{2}-\d{2}-\d{2}$/);
419	  return m ? m[1] : id;
420	}
421	
422	function fireMacNotification({ id, command }) {
423	  if (process.platform !== "darwin") return;
424	  try {
425	    const { spawn } = require("child_process");
426	    const msg = `GSD-T headless run complete: ${id}`;
427	    const script = `display notification "${msg}" with title "GSD-T" subtitle "${command}"`;
428	    const child = spawn("osascript", ["-e", script], {
429	      detached: true,
430	      stdio: "ignore",
431	    });
432	    child.unref();
433	  } catch (_) {
434	    /* graceful degradation */
435	  }
436	}
