438	// ── Token-Log Writer (Fix 1, v3.12.12) ───────────────────────────────────────
439	
440	const TOKEN_LOG_HEADER =
441	  "| Datetime-start | Datetime-end | Command | Step | Model | Duration(s) | Notes | Domain | Task | Ctx% |\n" +
442	  "|---|---|---|---|---|---|---|---|---|---|\n";
443	
444	/**
445	 * Append one row to {projectDir}/.gsd-t/token-log.md matching the schema used
446	 * by interactive command-file observability blocks.
447	 *
448	 * @param {string} projectDir
449	 * @param {{ dtStart: string, dtEnd: string, command: string, durationS: number, exitCode: number }} entry
450	 */
451	function appendTokenLog(projectDir, entry) {
452	  try {
453	    const logPath = path.join(projectDir, ".gsd-t", "token-log.md");
454	    const note = entry.exitCode === 0 ? "headless spawn: ok" : `headless spawn: exit ${entry.exitCode}`;
455	    // v3.12.14: prefer env-var model over the old hardcoded "unknown". The
456	    // parent session should have set GSD_T_MODEL before invoking spawn; fall
457	    // back to "unknown" if not (graceful).
458	    const model = process.env.GSD_T_MODEL || "unknown";
459	    const row =
460	      `| ${entry.dtStart} | ${entry.dtEnd} | ${entry.command} | headless | ${model} | ${entry.durationS}s | ${note} | - | - | unknown |\n`;
461	    if (!fs.existsSync(logPath)) {
462	      // Create with header
463	      ensureDir(path.dirname(logPath));
464	      fs.writeFileSync(logPath, `# GSD-T Token Log\n\n${TOKEN_LOG_HEADER}${row}`);
465	    } else {
466	      // Check if header row exists; if not prepend it (migration for files created before this fix)
467	      const existing = fs.readFileSync(logPath, "utf8");
468	      if (!existing.includes("| Datetime-start |")) {
469	        fs.writeFileSync(logPath, `# GSD-T Token Log\n\n${TOKEN_LOG_HEADER}${existing}${row}`);
470	      } else {
471	        fs.appendFileSync(logPath, row);
472	      }
473	    }
474	  } catch (_) {
475	    /* best-effort — never halt the completion watcher */
476	  }
477	}
478	
479	// ── Helpers ──────────────────────────────────────────────────────────────────
480	
481	function ensureDir(d) {
482	  if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true });
483	}
484	
485	function stripGsdtPrefix(command) {
486	  if (typeof command !== "string") return "";
487	  return command.replace(/^gsd-t-/, "");
488	}
